     9→import type {
    10→  BuybackResponse,
    11→  CreateBuybackRequest,
    12→} from "@/shared/types/buyback.types";
    13→import { toast } from "@/shared/ui/notification";
    14→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
    15→import { ApiKeys, TagsEnum } from "../query-keys";
    16→import { buybackService } from "../services/buyback";
    17→
    18→interface RenewBuybackRequest {
    19→  emailOtpId: string;
    20→  phoneOtpId: string;
    21→}
    22→
    23→export function useCreateBuyback() {
    24→  const queryClient = useQueryClient();
    25→
    26→  return useMutation({
    27→    mutationFn: async (data: CreateBuybackRequest): Promise<BuybackResponse> =>
    28→      buybackService.create(data),
    29→    onSuccess: () => {
    30→      toast.success("Buyback request created", {
    31→        description: "Your buyback request has been submitted successfully",
    32→      });
    33→
    34→      queryClient.invalidateQueries({
    35→        refetchType: "all",
    36→        predicate: (query) => {
    37→          const [tag, param] = query.queryKey;
    38→          const isListQuery = param === undefined || typeof param === "object";
    39→
    40→          return (
    41→            isListQuery &&
    42→            (tag === TagsEnum.BUYBACKS ||
    43→              tag === TagsEnum.BUYBACK_REQUESTS ||
    44→              tag === TagsEnum.ACTIVE_BUYBACKS ||
    45→              tag === TagsEnum.HISTORICAL_BUYBACKS)
    46→          );
    47→        },
    48→      });
    49→    },
    50→    onError: (error) => {
    51→      toast.error("Failed to create buyback", {
    52→        description: getErrorMessage(error, "Could not submit your request"),
    53→      });
    54→    },
    55→  });
    56→}
    57→
    58→export function useUpdateBuyback() {
    59→  const queryClient = useQueryClient();
    60→
    61→  return useMutation({
    62→    mutationFn: async ({
    63→      id,
    64→      data,
    65→    }: {
    66→      id: string;
    67→      data: Partial<CreateBuybackRequest>;
    68→    }): Promise<BuybackResponse> => buybackService.update(id, data),
    69→    onSuccess: () => {
    70→      toast.success("Buyback updated", {
    71→        description: "Your buyback request has been updated successfully",
    72→      });
    73→
    74→      queryClient.invalidateQueries({
    75→        refetchType: "all",
    76→        predicate: (query) => {
    77→          const [tag, param] = query.queryKey;
    78→          const isListQuery = param === undefined || typeof param === "object";
    79→
    80→          return (
    81→            isListQuery &&
    82→            (tag === TagsEnum.BUYBACKS ||
    83→              tag === TagsEnum.BUYBACK_REQUESTS ||
    84→              tag === TagsEnum.ACTIVE_BUYBACKS ||
    85→              tag === TagsEnum.HISTORICAL_BUYBACKS)
    86→          );
    87→        },
    88→      });
    89→    },
    90→    onError: (error) => {
    91→      toast.error("Failed to update buyback", {
    92→        description: getErrorMessage(error, "Could not update request"),
    93→      });
    94→    },
    95→  });
    96→}
    97→
    98→export function useBuybackDetails(id: string, enabled = true) {
    99→  return useQuery({
   100→    queryKey: ApiKeys.buybacks(id),
   101→    queryFn: () => buybackService.getDetails(id),
   102→    enabled: enabled && !!id,
   103→  });
   104→}
   105→
   106→export function useRenewBuyback() {
   107→  const queryClient = useQueryClient();
   108→
   109→  return useMutation({
   110→    mutationFn: ({
   111→      buybackId,
   112→      data,
   113→    }: {
   114→      buybackId: string;
   115→      data: RenewBuybackRequest;
   116→    }) => renewBuyback(buybackId, data),
   117→    onSuccess: () => {
   118→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests() });
   119→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybacks() });
   120→    },
   121→  });
   122→}
   123→
   124→export function useBuybackAsset() {
   125→  const queryClient = useQueryClient();
   126→
   127→  return useMutation({
   128→    mutationFn: ({
   129→      buybackId,
   130→      assetHandoverOption,
   131→      visitDate,
   132→    }: {
   133→      buybackId: string;
   134→      assetHandoverOption: AssetHandoverOption;
   135→      visitDate?: Date;
   136→    }) => buybackAsset(buybackId, { assetHandoverOption, visitDate }),
   137→    onSuccess: () => {
   138→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests() });
   139→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybacks() });
   140→      queryClient.invalidateQueries({ queryKey: ApiKeys.wallet() });
   141→    },
   142→  });
   143→}
   144→
   145→export function useCanRenewBuyback(buybackId: string, enabled = true) {
   146→  return useQuery({
   147→    queryKey: ApiKeys.canRenewBuyback(buybackId),
   148→    queryFn: () => checkCanRenewBuyback(buybackId),
   149→    enabled: enabled && !!buybackId,
   150→  });
   151→}
   152→
   153→export function useInitAssetReturn() {
   154→  const queryClient = useQueryClient();
   155→
   156→  return useMutation({
   157→    mutationFn: ({
   158→      buybackId,
   159→      assetHandoverOption,
   160→      visitDate,
   161→    }: {
   162→      buybackId: string;
   163→      assetHandoverOption: AssetHandoverOption;
   164→      visitDate?: Date;
   165→    }) => initAssetReturn(buybackId, { assetHandoverOption, visitDate }),
   166→    onSuccess: () => {
   167→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybackRequests() });
   168→      queryClient.invalidateQueries({ queryKey: ApiKeys.buybacks() });
   169→    },
   170→  });
   171→}
